import React from 'react';
import { Link } from 'react-router-dom';

export default function Footer() {
  const navLinks = [
    { to: '/', label: 'Home' },
    { to: '/coaching', label: 'Coaching' },
    { to: '/about', label: 'About' },
    { to: '/contact', label: 'Contact' },
    { to: 'mailto:fayzanrabcoaching@gmail.com', label: 'Email', external: true },
  ];

  return (
    <footer style={{
      borderTop: '1px solid rgba(255,255,255,0.06)',
      padding: '40px 24px',
      background: 'rgba(0,0,0,0.3)',
    }}>
      <div style={{
        maxWidth: '1100px',
        margin: '0 auto',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        flexWrap: 'wrap',
        gap: '20px',
      }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: '6px', marginBottom: '4px' }}>
            <span style={{
              fontFamily: "'Playfair Display', serif",
              fontSize: '16px',
              fontWeight: 700,
              color: '#f8f6ff',
            }}>Fayzan Rab</span>
            <span style={{
              fontSize: '11px',
              fontWeight: 600,
              letterSpacing: '0.1em',
              background: 'linear-gradient(135deg, #8b5cf6, #06b6d4)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text',
            }}>MD PCC</span>
          </div>
          <p style={{ fontSize: '12px', color: 'rgba(248,246,255,0.4)' }}>Doctor and Executive Coach.</p>
        </div>

        <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
          {navLinks.map(({ to, label, external }) =>
            external ? (
              <a
                key={to}
                href={to}
                style={{
                  padding: '6px 14px',
                  fontSize: '13px',
                  color: 'rgba(248,246,255,0.5)',
                  borderRadius: '100px',
                  transition: 'color 0.2s ease',
                  textDecoration: 'none',
                }}
              >
                {label}
              </a>
            ) : (
              <Link
                key={to}
                to={to}
                style={{
                  padding: '6px 14px',
                  fontSize: '13px',
                  color: 'rgba(248,246,255,0.5)',
                  borderRadius: '100px',
                  transition: 'color 0.2s ease',
                  textDecoration: 'none',
                }}
              >
                {label}
              </Link>
            )
          )}
        </div>
      </div>
    </footer>
  );
}
